CREATE TABLE external_analytics_to_roles
(
	id serial,
	external_analytic_id integer DEFAULT NULL,
	role_id integer DEFAULT NULL,
	CONSTRAINT pk_external_analytics_to_roles PRIMARY KEY (id)
	, CONSTRAINT fk_external_analytics_to_roles_to_external_analytic FOREIGN KEY (external_analytic_id) REFERENCES external_analytics (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE CASCADE
	, CONSTRAINT fk_external_analytics_to_roles_to_role FOREIGN KEY (role_id) REFERENCES roles (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE CASCADE
);
CREATE INDEX i_external_analytics_to_roles_external_analytic ON external_analytics_to_roles (external_analytic_id);
CREATE INDEX i_external_analytics_to_roles_role ON external_analytics_to_roles (role_id);

ALTER TABLE external_analytics ADD COLUMN IF NOT EXISTS is_public boolean DEFAULT true;
UPDATE external_analytics set is_public = true where is_public IS NULL;
